"""
飞书机器人 + 智谱 GLM 链接摘要服务（轮询模式）
功能：主动拉取飞书消息，调用智谱 GLM 生成摘要并返回
优点：不需要公网地址，不需要 ngrok
"""

import os
import json
import re
import time
import threading
from zhipuai import ZhipuAI
import requests

# ============ 配置区 ============

try:
    from feishu_bot_config import (
        ZHIPU_API_KEY,
        FEISHU_APP_ID,
        FEISHU_APP_SECRET,
        GLM_MODEL,
        MAX_CONTENT_LENGTH
    )
except ImportError:
    ZHIPU_API_KEY = os.getenv("ZHIPU_API_KEY", "")
    FEISHU_APP_ID = os.getenv("FEISHU_APP_ID", "")
    FEISHU_APP_SECRET = os.getenv("FEISHU_APP_SECRET", "")
    GLM_MODEL = os.getenv("GLM_MODEL", "glm-4-flash")
    MAX_CONTENT_LENGTH = int(os.getenv("MAX_CONTENT_LENGTH", 5000))

# 轮询间隔（秒）
POLL_INTERVAL = 3

# 飞书 API 基础 URL
FEISHU_API_BASE = "https://open.feishu.cn/open-apis"

# ============ 初始化 ============

zhipu_client = ZhipuAI(api_key=ZHIPU_API_KEY)

# 存储已处理的消息 ID，避免重复处理
processed_messages = set()

# 用于获取用户访问 token 的缓存
user_access_token = None
user_token_expires_at = 0

# ============ 工具函数 ============

def extract_urls(text):
    """从文本中提取 URL"""
    url_pattern = r'https?://[^\s<>"{}|\\^`\[\]]+'
    urls = re.findall(url_pattern, text)
    return list(set(urls))  # 去重

def get_tenant_access_token():
    """获取飞书 tenant_access_token"""
    url = f"{FEISHU_API_BASE}/auth/v3/tenant_access_token/internal"
    payload = {
        "app_id": FEISHU_APP_ID,
        "app_secret": FEISHU_APP_SECRET
    }
    try:
        response = requests.post(url, json=payload)
        data = response.json()
        if data.get("code") == 0:
            return data.get("tenant_access_token")
        else:
            print(f"获取 tenant_access_token 失败: {data}")
            return None
    except Exception as e:
        print(f"获取 tenant_access_token 异常: {e}")
        return None

def get_user_access_token():
    """获取用户访问 token（用于读取消息）"""
    global user_access_token, user_token_expires_at

    # 如果 token 还有效，直接返回
    if user_access_token and time.time() < user_token_expires_at:
        return user_access_token

    # 获取新的 token
    tenant_token = get_tenant_access_token()
    if not tenant_token:
        return None

    url = f"{FEISHU_API_BASE}/auth/v3/tenant_access_token/internal"
    # 注意：这里需要应用有用户身份权限
    # 实际使用时可能需要使用 OAuth 2.0 授权流程
    return tenant_token  # 简化版，使用 tenant token

def send_feishu_message(message_id, content):
    """发送消息回飞书"""
    token = get_tenant_access_token()
    if not token:
        return False

    url = f"{FEISHU_API_BASE}/im/v1/messages/{message_id}/reply"

    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json"
    }

    payload = {
        "msg_type": "text",
        "content": json.dumps({"text": content})
    }

    try:
        response = requests.post(url, headers=headers, json=payload)
        result = response.json()
        print(f"发送消息响应: {result}")
        return result.get("code") == 0
    except Exception as e:
        print(f"发送消息异常: {e}")
        return False

def fetch_url_content(url):
    """获取网页内容"""
    try:
        response = requests.get(url, timeout=10, headers={
            "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
        })
        if response.status_code == 200:
            content = response.text[:10000]
            return {
                "success": True,
                "content": content,
                "title": extract_title(response.text)
            }
        else:
            return {"success": False, "error": f"HTTP {response.status_code}"}
    except Exception as e:
        return {"success": False, "error": str(e)}

def extract_title(html):
    """从 HTML 中提取标题"""
    match = re.search(r'<title[^>]*>(.*?)</title>', html, re.IGNORECASE | re.DOTALL)
    if match:
        return match.group(1).strip()
    return "未知标题"

def generate_summary_with_glm(url, content_info):
    """使用智谱 GLM 生成链接摘要"""
    if not content_info.get("success"):
        return f"⚠️ 无法获取链接内容: {content_info.get('error', '未知错误')}"

    title = content_info.get("title", "未知标题")
    content = content_info.get("content", "")

    prompt = f"""请为以下网页内容生成一个简洁的摘要：

网页标题：{title}
网页链接：{url}

网页内容：
{content[:5000]}

请按以下格式输出（保持语言一致性）：

📎 **[网页标题]**

**核心内容：**
一句话概括。

**要点：**
• 要点1
• 要点2
• 要点3

如果内容无法访问或需要登录，请在开头注明。
"""

    try:
        response = zhipu_client.chat.completions.create(
            model=GLM_MODEL,
            messages=[
                {"role": "system", "content": "你是一个专业的内容摘要助手，擅长提取网页核心信息。"},
                {"role": "user", "content": prompt}
            ],
            temperature=0.3,
            max_tokens=1500
        )
        return response.choices[0].message.content
    except Exception as e:
        return f"❌ 摘要生成失败: {str(e)}"

def get_conversations(token):
    """获取会话列表"""
    url = f"{FEISHU_API_BASE}/im/v1/chats"
    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json"
    }

    try:
        response = requests.get(url, headers=headers)
        data = response.json()
        if data.get("code") == 0:
            return data.get("data", {}).get("items", [])
        else:
            print(f"获取会话列表失败: {data}")
            return []
    except Exception as e:
        print(f"获取会话列表异常: {e}")
        return []

def get_messages(token, chat_id, limit=20):
    """获取指定会话的消息列表"""
    url = f"{FEISHU_API_BASE}/im/v1/messages"
    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json"
    }
    params = {
        "container_id": chat_id,
        "container_id_type": "chat",
        "page_size": limit
    }

    try:
        response = requests.get(url, headers=headers, params=params)
        data = response.json()
        if data.get("code") == 0:
            return data.get("data", {}).get("items", [])
        else:
            print(f"获取消息列表失败: {data}")
            return []
    except Exception as e:
        print(f"获取消息列表异常: {e}")
        return []

def process_message(message):
    """处理单条消息"""
    global processed_messages

    message_id = message.get("message_id")

    # 跳过已处理的消息
    if message_id in processed_messages:
        return

    # 标记为已处理
    processed_messages.add(message_id)

    # 清理旧的消息 ID（避免内存无限增长）
    if len(processed_messages) > 1000:
        old_messages = list(processed_messages)[:500]
        for old_id in old_messages:
            processed_messages.discard(old_id)

    msg_type = message.get("msg_type")

    # 只处理文本消息
    if msg_type != "text":
        return

    try:
        content_json = json.loads(message.get("content", "{}"))
        user_text = content_json.get("text", "")
    except:
        return

    # 提取 URL
    urls = extract_urls(user_text)

    if urls:
        url = urls[0]
        print(f"\n[收到链接] {url}")

        # 发送"处理中"消息
        send_feishu_message(message_id, f"🔍 正在获取链接摘要: {url}")

        # 获取内容并生成摘要
        content_info = fetch_url_content(url)
        summary = generate_summary_with_glm(url, content_info)

        # 发送摘要
        send_feishu_message(message_id, f"{summary}\n\n🔗 原链接: {url}")
        print(f"[摘要已发送]")
    else:
        # 没有 URL，提示用户
        send_feishu_message(message_id, "💡 请发送一个链接，我会为你生成摘要。")

def polling_loop():
    """轮询主循环"""
    print("[轮询模式] 消息监听已启动...")
    print(f"[轮询间隔] {POLL_INTERVAL} 秒\n")

    while True:
        try:
            token = get_tenant_access_token()
            if not token:
                print("[错误] 无法获取访问 token，3秒后重试...")
                time.sleep(3)
                continue

            # 获取所有会话
            conversations = get_conversations(token)

            for conv in conversations:
                chat_id = conv.get("chat_id")
                if not chat_id:
                    continue

                # 获取该会话的消息
                messages = get_messages(token, chat_id, limit=10)

                # 处理每条消息（倒序，新的在前）
                for msg in reversed(messages):
                    # 只处理用户发送的消息（不是机器人自己发的）
                    sender = msg.get("sender", {})
                    sender_type = sender.get("sender_type", "")
                    if sender_type == "user":  # 只处理用户消息
                        process_message(msg)

        except Exception as e:
            print(f"[异常] 轮询过程出错: {e}")

        # 等待下一次轮询
        time.sleep(POLL_INTERVAL)

# ============ 主程序 ============

def main():
    print("=" * 60)
    print("飞书链接摘要机器人（轮询模式）")
    print("=" * 60)
    print(f"智谱模型: {GLM_MODEL}")
    print(f"轮询间隔: {POLL_INTERVAL} 秒")
    print(f"\n✅ 无需配置 Webhook URL")
    print(f"✅ 无需使用 ngrok")
    print(f"\n直接在飞书中给机器人发送链接即可！\n")
    print("=" * 60)

    # 检查配置
    if not ZHIPU_API_KEY or ZHIPU_API_KEY == "请填写你的智谱API_Key":
        print("\n⚠️ 警告: 请先配置 ZHIPU_API_KEY")
        return
    if not FEISHU_APP_ID or FEISHU_APP_ID == "请填写你的飞书App_ID":
        print("⚠️ 警告: 请先配置 FEISHU_APP_ID")
        return

    # 启动轮询
    polling_loop()

if __name__ == "__main__":
    main()

